// Token France Travail CACHÉ (static data) avec expiration : il est valide ~25 min
// -> inutile de le redemander à chaque profil ET à chaque run. Refetch seulement
// s'il a expiré (marge 60s). 10 profils -> ~1 fetch / 25 min. Tolérant.
const sd = $getWorkflowStaticData('global');
const now = Date.now();
if (sd.ftToken && sd.ftTokenExp && now < sd.ftTokenExp) {
  return [{ json: sd.ftToken }];
}
const body = new URLSearchParams({
  grant_type: 'client_credentials',
  client_id: $env.FRANCE_TRAVAIL_CLIENT_ID || '',
  client_secret: $env.FRANCE_TRAVAIL_CLIENT_SECRET || '',
  scope: 'api_offresdemploiv2 o2dsoffre',
}).toString();
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://entreprise.francetravail.fr/connexion/oauth2/access_token?realm=/partenaire',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body,
  });
  const tok = typeof resp === 'string' ? JSON.parse(resp) : resp;
  sd.ftToken = tok;
  sd.ftTokenExp = now + (((tok.expires_in || 1499) - 60) * 1000);
  return [{ json: tok }];
} catch (e) {
  return [];
}

