// Normaliseurs par source : réponse brute d'une API/flux -> offres au schéma
// commun (champs de la table `offers`, hors hash/score qui sont ajoutés ensuite
// par annotate() de offer-utils.mjs).
//
// Source de vérité de ce mapping. Dans n8n, chaque source a un nœud Code qui
// colle le corps du normaliseur correspondant. Testé par sources.test.mjs.

const s = (v) => String(v ?? "").trim();

/** Adzuna : { results: [...] } — GET /v1/api/jobs/fr/search/{page}. */
function normalizeAdzuna(payload) {
  const results = payload?.results ?? [];
  return results.map((r) => ({
    source: "adzuna",
    source_id: s(r.id),
    title: s(r.title),
    company: s(r.company?.display_name),
    location: s(r.location?.display_name),
    contract_type: s(r.contract_time || r.contract_type),
    salary: r.salary_min ? s(r.salary_min) : "",
    description: s(r.description),
    url: s(r.redirect_url),
  }));
}

/** France Travail : { resultats: [...] } — Offres d'emploi v2 /offres/search. */
function normalizeFranceTravail(payload) {
  const results = payload?.resultats ?? [];
  return results.map((r) => ({
    source: "france_travail",
    source_id: s(r.id),
    title: s(r.intitule),
    company: s(r.entreprise?.nom),
    location: s(r.lieuTravail?.libelle),
    contract_type: s(r.typeContrat || r.typeContratLibelle),
    salary: s(r.salaire?.libelle),
    description: s(r.description),
    url: s(r.origineOffre?.urlOrigine),
  }));
}

/**
 * JobSpy : déjà normalisé par le micro-service (services/jobspy) sous
 * { count, offers: [...] }. On revalide juste la forme et on force la source.
 */
function normalizeJobSpy(payload) {
  const offers = payload?.offers ?? [];
  return offers.map((o) => ({
    source: s(o.source) || "jobspy",
    source_id: s(o.source_id || o.url),
    title: s(o.title),
    company: s(o.company),
    location: s(o.location),
    contract_type: s(o.contract_type),
    salary: s(o.salary),
    description: s(o.description),
    url: s(o.url),
  }));
}

/**
 * Welcome to the Jungle (RSS) : liste d'items { title, link, contentSnippet,
 * content, isoDate }. Pas d'entreprise fiable dans le flux ; on tente de
 * l'extraire d'un titre au format "Poste - Entreprise".
 */
function normalizeWTTJ(items) {
  const list = items ?? [];
  return list.map((it) => {
    const rawTitle = s(it.title);
    let title = rawTitle;
    let company = "";
    const dash = rawTitle.split(/\s[-–|]\s/);
    if (dash.length >= 2) {
      title = s(dash[0]);
      company = s(dash[dash.length - 1]);
    }
    return {
      source: "wttj",
      source_id: s(it.guid || it.id || it.link),
      title,
      company,
      location: s(it.location),
      contract_type: "",
      salary: "",
      description: s(it.contentSnippet || it.content || it.description),
      url: s(it.link),
    };
  });
}

/**
 * Google Jobs via SerpApi : { jobs_results: [...] }. Source principale du
 * pipeline Make réel. URL : on prend le 1er lien de candidature / partage dispo.
 */
function normalizeGoogleJobs(payload) {
  const results = payload?.jobs_results ?? [];
  return results.map((r) => {
    const ext = r.detected_extensions ?? {};
    const url =
      r.share_link ||
      (Array.isArray(r.apply_options) && r.apply_options[0]?.link) ||
      (Array.isArray(r.related_links) && r.related_links[0]?.link) ||
      "";
    return {
      source: "google_jobs",
      source_id: s(r.job_id),
      title: s(r.title),
      company: s(r.company_name),
      location: s(r.location),
      contract_type: s(ext.schedule_type),
      salary: s(ext.salary),
      description: s(r.description),
      url: s(url),
    };
  });
}

/**
 * JSearch (RapidAPI) : { data: [...] } — agrégateur LinkedIn/Indeed/Glassdoor
 * via API officielle (alternative fiable au scraping JobSpy). Forme de réponse
 * vérifiée sur un workflow n8n fonctionnel. `source` = jsearch:<publisher>.
 */
function normalizeJSearch(payload) {
  const results = payload?.data ?? [];
  return results.map((r) => {
    const publisher = s(r.job_publisher).toLowerCase().replace(/\s+/g, "-");
    return {
      source: publisher ? `jsearch:${publisher}` : "jsearch",
      source_id: s(r.job_id),
      title: s(r.job_title),
      company: s(r.employer_name),
      location: s(r.job_city || r.job_location),
      contract_type: s(r.job_employment_type),
      salary: s(r.job_salary_string),
      description: s(r.job_description),
      url: s(r.job_apply_link || r.job_google_link),
    };
  });
}

/**
 * La Bonne Alternance (service public apprentissage / beta.gouv) — API emploi
 * unifiée v3 : GET https://api.apprentissage.beta.gouv.fr/api/job/v1/search
 * (params romes + latitude/longitude + radius ; clé API en Bearer).
 *
 * La réponse contient DEUX listes au schéma "offre" normalisé :
 *  - `jobs`       : offres d'alternance publiées -> pipeline offres classique ;
 *  - `recruiters` : entreprises à fort potentiel d'embauche, SANS offre publiée,
 *                   à contacter en CANDIDATURE SPONTANÉE (cf. normalizeLBARecruiters).
 *
 * Forme VÉRIFIÉE sur un vrai appel (2026-06-28, auth `Bearer`, zone Valenciennes/
 * Lille, rome M1805) et verrouillée par des fixtures réelles dans sources.test.mjs.
 * Note : les jobs partenaires (France Travail) ont `workplace.{brand,name,
 * legal_name}` à null -> `company` vide (dégradation propre, jamais d'invention).
 */
function normalizeLaBonneAlternanceJobs(payload) {
  const jobs = payload?.jobs ?? [];
  return jobs.map((j) => {
    const wp = j.workplace ?? {};
    const types = j.contract?.type;
    return {
      source: "la_bonne_alternance",
      source_id: s(j.identifier?.id || j.identifier?.partner_job_id),
      title: s(j.offer?.title),
      company: s(wp.brand || wp.name || wp.legal_name),
      location: s(wp.location?.address),
      contract_type: s(Array.isArray(types) ? types.join(", ") : types) || "Alternance",
      salary: "",
      description: s(j.offer?.description),
      url: s(j.apply?.url),
    };
  });
}

/**
 * La Bonne Alternance — volet "entreprises à contacter" (candidature spontanée).
 * Renvoie des fiches ENTREPRISE (schéma proche de la table `companies`), pas des
 * offres : pas de description de poste, mais un lien/contact de candidature.
 */
function normalizeLBARecruiters(payload) {
  const recruiters = payload?.recruiters ?? [];
  return recruiters.map((r) => {
    const wp = r.workplace ?? {};
    return {
      source: "la_bonne_alternance",
      source_id: s(r.identifier?.id || wp.siret),
      name: s(wp.brand || wp.name || wp.legal_name),
      siret: s(wp.siret),
      sector: s(wp.domain?.naf?.label || wp.naf?.label),
      website: s(wp.website),
      location: s(wp.location?.address),
      apply_url: s(r.apply?.url),
      phone: s(r.apply?.phone),
      email: s(r.apply?.email || r.contact?.email || wp.email),
    };
  });
}

const NORMALIZERS = {
  adzuna: normalizeAdzuna,
  france_travail: normalizeFranceTravail,
  jobspy: normalizeJobSpy,
  wttj: normalizeWTTJ,
  google_jobs: normalizeGoogleJobs,
  jsearch: normalizeJSearch,
  la_bonne_alternance: normalizeLaBonneAlternanceJobs,
};

// --- driver: norm FT (réponse France Travail -> schéma commun) ---
return normalizeFranceTravail($input.first().json).map((o) => ({ json: o }));

