// --- driver: norm JobSpy (réponse du micro-service -> schéma commun) ---
return normalizeJobSpy($input.first().json).map((o) => ({ json: o }));

// Dédup des appels LBA : LBA ne dépend que de (lat,long,ROME,rayon), pas des
// mots-clés -> inutile de l'appeler pour chaque profil d'une même ville. Seul le
// PREMIER profil de chaque géo appelle l'API ; les autres skippent (10 -> 2 appels).
const prof = $('Boucle profils').first().json;
const all = $('Profils actifs').all().map((i) => i.json);
const geoKey = (x) => `${x.latitude},${x.longitude},${x.rome_codes},${x.radius_km}`;
if (!prof.latitude || !prof.rome_codes) return [];
const firstForGeo = all.find((x) => geoKey(x) === geoKey(prof));
if (!firstForGeo || firstForGeo.id !== prof.id) return [];
const url = 'https://api.apprentissage.beta.gouv.fr/api/job/v1/search?' + new URLSearchParams({
  romes: prof.rome_codes, latitude: prof.latitude, longitude: prof.longitude, radius: prof.radius_km || 30,
});
try {
  const resp = await this.helpers.httpRequest({ method: 'GET', url, headers: { Authorization: 'Bearer ' + $env.LBA_API_KEY }, json: true });
  return [{ json: resp }];
} catch (e) {
  return [{ json: { jobs: [], recruiters: [] } }];
}

